// ============================================================
// InitCore v1.0 — API Adapter
// Autentica por Bearer token y aplica rate limiting simple
// mediante una tabla en memoria (staticData del workflow).
// Para producción seria, mover el rate limit a Redis.
// ============================================================

const headers = $input.first().json.headers || {};
const auth = headers['authorization'] || headers['Authorization'] || '';
if (!auth.startsWith('Bearer ')) {
  return [{ json: { valid: false, reason: 'Falta Authorization Bearer', status: 'rejected' } }];
}
const token = auth.replace('Bearer ', '').trim();

// Tokens permitidos — en producción, consultar tabla en BD
const allowedTokens = (($env.API_BEARER_TOKENS || '').split(',').map(s => s.trim()).filter(Boolean));
if (!allowedTokens.includes(token)) {
  return [{ json: { valid: false, reason: 'Token inválido', status: 'rejected' } }];
}

// Rate limiting: 100 req/min por token
const staticData = $getWorkflowStaticData('global');
staticData.rateLimits = staticData.rateLimits || {};
const now = Date.now();
const windowStart = now - 60 * 1000;
const bucket = staticData.rateLimits[token] || [];
const recent = bucket.filter(t => t > windowStart);
recent.push(now);
staticData.rateLimits[token] = recent;
if (recent.length > 100) {
  return [{ json: { valid: false, reason: 'Rate limit excedido (100/min)', status: 'rate_limited' } }];
}

const body = $input.first().json.body || {};
if (!body.text || !body.text.trim()) {
  return [{ json: { valid: false, reason: 'Campo text obligatorio', status: 'rejected' } }];
}

return [{ json: { valid: true, body, token_hint: token.substring(0, 12) + '...' } }];

const crypto = require('crypto');
const sha256 = s => crypto.createHash('sha256').update(String(s),'utf-8').digest('hex');
const stripHtml = html => !html ? '' : String(html)
  .replace(/<script[\s\S]*?<\/script>/gi,'')
  .replace(/<style[\s\S]*?<\/style>/gi,'')
  .replace(/<\/?[^>]+>/g,'')
  .replace(/&nbsp;/gi,' ').replace(/&amp;/gi,'&').replace(/&lt;/gi,'<')
  .replace(/&gt;/gi,'>').replace(/&quot;/gi,'"').replace(/&#39;|&apos;/gi,"'")
  .replace(/\s+/g,' ').trim();
const normForHash = t => (t||'').toLowerCase().normalize('NFD').replace(/[\u0300-\u036f]/g,'').replace(/[^\p{L}\p{N}]+/gu,' ').replace(/\s+/g,' ').trim();

// Convertir body de API a formato InitCore
const b = $input.first().json.body;
const user = b.user || {};
const identifier = user.id || user.email || `api-anon-${Date.now()}`;

const payload = {
  channel: 'api',
  message: { text: (b.text || '').substring(0, 5000), media: Array.isArray(b.media) ? b.media : [] },
  timestamp: b.timestamp || new Date().toISOString(),
  context: {
    name: user.name || '',
    email: user.email || '',
    phone: user.phone || '',
    language: (user.language || '').toLowerCase()
  },
  metadata: {
    source: 'api_adapter',
    adapter_version: '1.0.0',
    external_user_id: user.id || '',
    source_app: (b.metadata && b.metadata.source_app) || 'unknown',
    ...(b.metadata || {}),
    token_hint: $('Auth + rate limit').first().json.token_hint
  },
  status: 'pending',
  _user_identifier: identifier
};
const message_id = crypto.randomUUID();
const sender_id = sha256(payload.channel + ':' + payload._user_identifier);
const cleanText = stripHtml(payload.message?.text || '');
const mediaFingerprint = (payload.message?.media||[]).map(m => m.url || m.file_id || '').join('|');
const hashKey = normForHash(cleanText);
const hash = sha256(payload.channel + ':' + sender_id + ':' + (hashKey || mediaFingerprint || message_id));

// Flatten out the response so it is easy to persist to messages table, AND hold the 5 fields
const newPayload = {
  channel: payload.channel,
  message_id: message_id,
  sender_id: sender_id,
  user_id: sender_id, // keep it around for the messages table insert
  text: cleanText,
  hash: hash,
  media: payload.message?.media || [],
  ts: payload.timestamp || new Date().toISOString(),
  context: payload.context || {},
  metadata: payload.metadata || {}
};

return [{ json: newPayload }];
